import React from 'react';
import type { Meta } from '@storybook/react';
import { PinInput, PinInputField, InputNumber, Space, Divider } from '../..';
import { KeyboardKey } from '@universe-design/react-utilities';
import { usePinInputContext } from '../usePinInput';

export default {
  title: 'Components/PinInput/临时示例',
} satisfies Meta;

const DynamicField = () => {
  const [count, setCount] = React.useState(4);
  const { size } = usePinInputContext();
  React.useEffect(() => {
    const cb = (ev: KeyboardEvent) => {
      if (ev.key === KeyboardKey.ArrowUp) {
        setCount(o => o + 1);
        return;
      }
      if (ev.key === KeyboardKey.ArrowDown) {
        setCount(o => o - 1);
        return;
      }
    };
    document.addEventListener('keydown', cb);
    return () => {
      document.removeEventListener('keydown', cb);
    };
  });
  return (
    <Space>
      <InputNumber
        size={size}
        value={count}
        onChange={v => {
          if (typeof v === 'number') {
            setCount(v);
          }
        }}
      />
      {Array(count)
        .fill(0)
        .map((o, i) => (
          <PinInputField key={i} />
        ))}
    </Space>
  );
};

export const DynamicFieldDemo = () => (
  <>
    <Divider>Small</Divider>
    <PinInput size="small">
      <DynamicField />
    </PinInput>
    <Divider>Medium</Divider>
    <PinInput size="medium">
      <DynamicField />
    </PinInput>
  </>
);
